2.4￿￿系统频率响应的意义

b=[0.05 0.05];%构造系统函数
a=[1 -0.9];
n=[0:99];
N=100;fs=1000;
x=sin(2*pi*10*n/fs)+sin(2*pi*250*n/fs);
y=filter(b,a,x);%求系统输出

figure(1)
zplane(b,a);%画零极点图

figure(2)
subplot(211);plot(n,x);
subplot(212);plot(n,y);
简单一阶滤波器的设计

figure(3)
Fx=fft(x);%画输入x(n)的频谱
subplot(311);
plot(n*fs/N,abs(Fx)/max(abs(Fx)));

[Hh,wh]=freqz(b,a,’whole’); %画系统h(n)的频谱
subplot(312); plot(wh/pi,abs(Hh));

Fy=fft(y); %画输出y(n)的频谱
subplot(313); plot(n*fs/N,abs(Fy)/max(abs(Fy)));
